export const subscriptionPlanSchema = {
  $schema: 'https://json-schema.org/draft/2020-12/schema',
  $id: 'https://ai-sdlc.io/schemas/v1alpha1/subscription-plan.schema.json',
  title: 'AI-SDLC SubscriptionPlan',
  description:
    'Declares the billing-window characteristics of a harness so the SubscriptionLedger can pace dispatch correctly (RFC-0010 §6.6 / §14).',
  type: 'object',
  required: ['apiVersion', 'kind', 'metadata', 'spec'],
  properties: {
    apiVersion: {
      $ref: 'common.schema.json#/$defs/apiVersion',
    },
    kind: {
      type: 'string',
      const: 'SubscriptionPlan',
    },
    metadata: {
      $ref: 'common.schema.json#/$defs/metadata',
    },
    spec: {
      type: 'object',
      required: ['harness', 'billingMode'],
      properties: {
        harness: {
          type: 'string',
          description:
            'Name of the registered harness this plan applies to (e.g., claude-code, codex).',
        },
        billingMode: {
          type: 'string',
          enum: ['session-window', 'monthly-cap', 'pay-per-token'],
          description: 'How the vendor meters consumption.',
        },
        windowDuration: {
          type: 'string',
          description:
            'ISO 8601 duration (e.g., PT5H) of the rolling window. Required when billingMode is session-window.',
        },
        windowQuotaTokens: {
          type: 'integer',
          minimum: 1,
          description:
            'Documented quota per window. Required when billingMode is session-window or monthly-cap.',
        },
        offPeak: {
          type: 'object',
          description: 'Off-peak multiplier configuration. Absent → no off-peak preference.',
          required: ['enabled', 'multiplier'],
          properties: {
            enabled: { type: 'boolean' },
            multiplier: {
              type: 'number',
              exclusiveMinimum: 1,
              description:
                'Token allocation multiplier during off-peak (e.g., 2.0 for Claude Code 2x).',
            },
            schedule: {
              type: 'array',
              description: 'Operator-declared off-peak time ranges; verified against vendor docs.',
              items: {
                type: 'object',
                required: ['tz', 'hours'],
                properties: {
                  tz: { type: 'string', description: 'IANA timezone (e.g., America/Los_Angeles).' },
                  hours: { type: 'string', description: "Hour range like '22-06'." },
                  daysOfWeek: {
                    type: 'string',
                    description: "Optional comma list (e.g., 'Sat,Sun').",
                  },
                },
                additionalProperties: false,
              },
            },
            lastVerified: {
              type: 'string',
              format: 'date',
              description:
                'ISO 8601 date the operator last confirmed the schedule against vendor docs (RFC-0010 §14.5).',
            },
          },
          additionalProperties: false,
        },
        pacingTarget: {
          type: 'number',
          minimum: 0,
          maximum: 1,
          default: 0.8,
          description: 'Target window utilization fraction at window-end.',
        },
        hardCap: {
          type: 'number',
          minimum: 0,
          maximum: 1,
          default: 0.95,
          description:
            'Above this fraction, the orchestrator refuses to dispatch new work even with schedule: now.',
        },
        quotaSource: {
          type: 'string',
          enum: ['self-tracked', 'authoritative-api', 'authoritative-with-fallback'],
          default: 'self-tracked',
          description:
            'Source of authoritative window state; see RFC-0010 §14.11 migration semantics.',
        },
      },
      additionalProperties: false,
      allOf: [
        {
          if: { properties: { billingMode: { const: 'session-window' } } },
          then: { required: ['windowDuration', 'windowQuotaTokens'] },
        },
        {
          if: { properties: { billingMode: { const: 'monthly-cap' } } },
          then: { required: ['windowQuotaTokens'] },
        },
      ],
    },
  },
  additionalProperties: false,
} as const;

export const substrateContractV1Schema = {
  $schema: 'https://json-schema.org/draft/2020-12/schema',
  $id: 'https://ai-sdlc.io/schemas/v1alpha1/substrate-contract.v1.schema.json',
  title: 'AI-SDLC SubstrateContract',
  description:
    'RFC-0028 Substrate Contract — typed, per-Soul-DID configuration object that shared substrate code reads from. Per-soul behavior emerges from contract values; the substrate has no soul-specific conditionals (the §7.2 AST scan target). Phase 1 (AISDLC-452) ships the minimum surface needed to declare the field-level `identityClass` discriminant with the canonical `core | evolving` taxonomy enumerated per §7.1 v0.2 resolution. Phases 2-5 (AISDLC-453..456) wire CI integrity assertions, structural drift detection, and operator runbooks against this schema.',
  type: 'object',
  required: ['apiVersion', 'kind', 'metadata', 'spec'],
  additionalProperties: false,
  properties: {
    apiVersion: {
      $ref: 'common.schema.json#/$defs/apiVersion',
    },
    kind: {
      type: 'string',
      const: 'SubstrateContract',
    },
    metadata: {
      $ref: 'common.schema.json#/$defs/metadata',
    },
    spec: {
      type: 'object',
      required: ['soulId', 'fields'],
      additionalProperties: false,
      properties: {
        soulId: {
          type: 'string',
          description:
            'Soul DID identifier this contract binds to. Must match a `tessellation.souls[]` entry (CI integrity assertion in Phase 2).',
          minLength: 1,
        },
        fields: {
          type: 'array',
          description:
            'Substrate Contract fields. Each field carries an `identityClass` discriminant per RFC-0028 §7.1 v0.2 resolution (canonical `core | evolving` taxonomy). Fields without an explicit `identityClass` default to `core` per the conservative novel-field rule (promotion to `evolving` requires RFC amendment with Design + Engineering sign-off).',
          items: {
            $ref: '#/$defs/SubstrateContractField',
          },
          default: [],
        },
      },
    },
  },
  $defs: {
    IdentityClass: {
      type: 'string',
      description:
        'Canonical RFC-0028 §7.1 v0.2 taxonomy. `core` = cannot be loosened by child Soul DIDs; pivot rescoring fires on change. `evolving` = free movement within tightening-only bounds; admission-queue rescoring only.',
      enum: ['core', 'evolving'],
    },
    SubstrateContractField: {
      type: 'object',
      description:
        'A single field on a Substrate Contract. Per RFC-0028 §3.2 universal invariants, every field MUST document its named consumer, default-fallback semantic, and inheritance class (`identityClass`). The no-dead-wires rule applies: a field without a named consumer is admissible-as-dead and must be removed or wired before the contract ships.',
      required: ['name', 'namedConsumer', 'defaultFallback'],
      additionalProperties: false,
      properties: {
        name: {
          type: 'string',
          description:
            'Field name. When listed in the canonical RFC-0028 §7.1 taxonomy (`requiresTenantPhysicalIsolation`, `observerCooldownMs`, etc.), the `identityClass` discriminant SHOULD match the canonical bucket. Novel field names default to `core`.',
          minLength: 1,
        },
        identityClass: {
          $ref: '#/$defs/IdentityClass',
          description:
            'Canonical inheritance class per RFC-0028 §7.1. Omit to opt into the novel-field default of `core` (a warning is emitted by `defaultIdentityClassForNovelField` to surface the missing classification to authors).',
        },
        namedConsumer: {
          type: 'string',
          description:
            'Repo-relative path or symbol identifying the substrate file/function that reads this value. Required per RFC-0028 §3.2 no-dead-wires rule.',
          minLength: 1,
        },
        defaultFallback: {
          type: 'string',
          description:
            'Plain-text description of what happens if the field is absent. The substrate MUST NOT silently drop behavior — every field documents its fallback semantic.',
          minLength: 1,
        },
        complianceLockKind: {
          type: 'string',
          description:
            'When set, indicates the field is a tightening-only compliance lock per RFC-0028 §6. `boolean-locked` types as `true` literal; `numeric-cap` types as bounded discriminated union; `categorical` enforces inheritance via TypeScript template-literal types.',
          enum: ['boolean-locked', 'numeric-cap', 'categorical'],
        },
      },
    },
  },
} as const;

export const variantConfigSchema = {
  $schema: 'https://json-schema.org/draft/2020-12/schema',
  $id: 'https://ai-sdlc.io/schemas/v1alpha1/variant-config.schema.json',
  title: 'AI-SDLC variant-config.yaml',
  description:
    "Per-organization variant configuration schema per RFC-0017 §10.1. Ships as '.ai-sdlc/variant-config.yaml' (per-org defaults). Per-Soul overrides may live in the soul's own spec.variantConfig block. Default constants: softWarnAt=5 (Miller 7±2 cognitive-load threshold), hardLimit=20 (re-architect-as-multi-soul threshold per RFC-0009 §3).",
  type: 'object',
  properties: {
    variant: {
      type: 'object',
      description: 'Top-level variant configuration block.',
      properties: {
        limits: {
          type: 'object',
          description:
            'OQ-1 — per-org variant count thresholds. Defaults: softWarnAt=5, hardLimit=20.',
          properties: {
            softWarnAt: {
              type: 'integer',
              minimum: 1,
              description:
                "Variant count at which a non-blocking Decision 'variant-count-soft-warning' is emitted. Default 5 (Miller 7±2 cognitive-load threshold).",
            },
            hardLimit: {
              type: 'integer',
              minimum: 1,
              description:
                "Variant count at which declaration is rejected with Decision 'variant-count-hard-limit-exceeded' plus a clarification task recommending multi-soul re-architecture. Default 20 (re-architect threshold per RFC-0009 §3). MUST be greater than softWarnAt.",
            },
          },
          additionalProperties: false,
        },
        lifecycle: {
          type: 'object',
          description: 'OQ-3 — variant deprecation and removal lifecycle.',
          properties: {
            deprecationWindowDays: {
              type: 'integer',
              minimum: 1,
              description:
                "Default deprecation window in days before a variant may be hard-removed. Default 30 (internal-config cadence). Per-Soul override via soul's spec.variantConfig.lifecycle.deprecationWindowDays.",
            },
            routing: {
              type: 'object',
              description: 'Decision-Catalog routing for variant lifecycle events.',
              properties: {
                onDeclared: {
                  type: 'string',
                  enum: ['log-catalog-no-interrupt'],
                  description:
                    'Action when deprecation declared. Default: log to Decision Catalog without interrupting the pipeline.',
                },
                onApproaching: {
                  type: 'string',
                  enum: ['operator-batch-surface'],
                  description:
                    'Action when deprecation window is approaching. Default: surface in operator batch review.',
                },
                onConsumersPending: {
                  type: 'string',
                  enum: ['degraded-mode-and-migration-tasks'],
                  description:
                    'Action when removal requested but consumers still reference the variant. Default: keep variant in degraded mode and emit migration tasks.',
                },
              },
              additionalProperties: false,
            },
          },
          additionalProperties: false,
        },
        scoring: {
          type: 'object',
          description: 'OQ-4 — cross-variant aggregation rule.',
          properties: {
            crossVariantAggregation: {
              type: 'string',
              enum: ['min', 'max', 'mean'],
              description:
                "Default cross-variant aggregation rule. Default 'min' — matches RFC-0009 §7.2 cross-soul default. Per-Soul override via soul's spec.variantConfig.scoring.crossVariantAggregation.",
            },
          },
          additionalProperties: false,
        },
        overrides: {
          type: 'object',
          description:
            'OQ-5 (revised 2026-05-26) — framework-owned designOverrides fields and adopter extension policy.',
          properties: {
            framework: {
              type: 'array',
              description:
                'Closed enum of framework-owned designOverrides field names. Expanding requires RFC amendment with Design Authority sign-off.',
              items: {
                type: 'string',
                enum: [
                  'colorPaletteOverlay',
                  'densityProfile',
                  'typographyScale',
                  'motionProfile',
                  'radiusProfile',
                ],
              },
            },
            adopterExtensionsAllowed: {
              type: 'boolean',
              description:
                "Whether adopters may extend designOverrides via vendor reverse-DNS prefix (e.g. 'acme.com/accessibilityProfile'). Default true.",
            },
          },
          additionalProperties: false,
        },
        uri: {
          type: 'object',
          description: 'OQ-6 — variant URI format convention.',
          properties: {
            format: {
              type: 'string',
              description:
                "Path-style URI format template per RFC-0017 OQ-6 resolution. The explicit 'variant:' keyword preserves the parent/child hierarchy.",
            },
          },
          additionalProperties: false,
        },
        authority: {
          type: 'object',
          description: 'OQ-7 — variant declaration authority model.',
          properties: {
            declarationOwner: {
              type: 'string',
              enum: ['design'],
              description:
                "Which authority owns variant declarations. Always 'design' per RFC-0017 OQ-7 + RFC-0029 Principle 1.",
            },
            substrateCostReview: {
              type: 'object',
              description: 'Engineering review routing for substrate-cost concerns.',
              properties: {
                reviewer: {
                  type: 'string',
                  enum: ['engineering'],
                },
                routing: {
                  type: 'string',
                  enum: ['decision-catalog'],
                },
                blockDecision: {
                  type: 'string',
                  description:
                    'Decision Catalog key emitted when Engineering blocks on substrate cost.',
                },
              },
              additionalProperties: false,
            },
          },
          additionalProperties: false,
        },
        cardinality: {
          type: 'object',
          description: 'OQ-8 — cardinality field activation policy.',
          properties: {
            activationThreshold: {
              type: 'object',
              properties: {
                adopterRequests: {
                  type: 'integer',
                  minimum: 1,
                  description:
                    'Number of distinct adopter requests before cardinality activation is auto-promoted to operator batch review. Default 2.',
                },
              },
              additionalProperties: false,
            },
            routing: {
              type: 'string',
              enum: ['decision-catalog-auto-promote'],
              description: 'How cardinality activation requests are routed.',
            },
          },
          additionalProperties: false,
        },
      },
      additionalProperties: false,
    },
  },
  additionalProperties: false,
} as const;

export const vectorStoreEntryV1Schema = {
  $schema: 'https://json-schema.org/draft/2020-12/schema',
  $id: 'https://ai-sdlc.dev/schemas/vector-store-entry.v1.schema.json',
  title: 'VectorStoreEntry',
  description:
    'JSON Schema for the VectorStoreEntry shape per RFC-0019 §8.1. Defines the format of each line in the JSONL embedding storage backend files at <artifactsDir>/_embeddings/<provider>-<modelVersion>.jsonl.',
  type: 'object',
  required: [
    'vector',
    'embeddingProvider',
    'embeddingModelVersion',
    'writtenAt',
    'text',
    'textHash',
  ],
  additionalProperties: false,
  properties: {
    vector: {
      type: 'array',
      description:
        "The embedding vector. Length MUST equal the adapter's declared dimensions at write time.",
      items: {
        type: 'number',
      },
      minItems: 1,
    },
    embeddingProvider: {
      type: 'string',
      description:
        "adapter.name at write time (e.g., 'openai-text-embedding-3-small'). Together with embeddingModelVersion, forms the provenance identity of this vector. Vectors from different providers are NOT interchangeable.",
      minLength: 1,
    },
    embeddingModelVersion: {
      type: 'string',
      description:
        "adapter.modelVersion at write time (e.g., '2024-01-25'). Together with embeddingProvider, forms the provenance identity of this vector. Allows migration tooling (cli-embedding-bump) to detect stale vectors from retired snapshots.",
      minLength: 1,
    },
    writtenAt: {
      type: 'string',
      description:
        'ISO 8601 timestamp of when this entry was written. Used by cli-embedding-gc for mtime-based retention.',
      format: 'date-time',
    },
    text: {
      type: 'string',
      description:
        'Original source text. REQUIRED — needed for re-embedding during migration (cli-embedding-bump). Adopters with privacy concerns MAY store text in a separate encrypted store and reference it by textHash.',
      minLength: 1,
    },
    textHash: {
      type: 'string',
      description:
        "SHA-256 hex digest of the source text. Used as a read-side cache key ('have we already embedded this exact text?') and for content-addressable storage lookup. Recomputing on every lookup is wasteful; storing separately avoids that.",
      pattern: '^[0-9a-f]{64}$',
    },
    metadata: {
      type: 'object',
      description:
        "Adopter-defined metadata. Examples: {sourceDoc: 'rfc-0009.md', shardId: 'OQ-6'}, {consumerLabel: 'rfc-0009-tessellation-drift'}. Opaque to the framework.",
      additionalProperties: true,
    },
  },
} as const;

export const workItemSchema = {
  $schema: 'https://json-schema.org/draft/2020-12/schema',
  $id: 'https://ai-sdlc.io/schemas/v1alpha1/work-item.schema.json',
  title: 'AI-SDLC WorkItem',
  description:
    'A backlog work item with optional soul and variant targeting for admission scoring. Implements RFC-0009 §5.3 targetedSouls and RFC-0017 §5.4 targetedVariants.',
  type: 'object',
  required: ['id', 'title'],
  properties: {
    id: {
      type: 'string',
      description: 'Canonical work item identifier (e.g. AISDLC-313).',
      minLength: 1,
    },
    title: {
      type: 'string',
      description: 'Human-readable title for the work item.',
      minLength: 1,
    },
    description: {
      type: 'string',
      description: 'Optional longer description.',
    },
    labels: {
      type: 'array',
      description: 'Classification labels.',
      items: { type: 'string' },
    },
    targetedSouls: {
      type: 'array',
      description:
        'Soul DID URIs this work item explicitly targets per RFC-0009 §5.3 (targetedSouls field). Drives soul-scope admission scoring. Empty = substrate-only (min-over-all-souls degenerate case per RFC-0009 §6).',
      items: {
        type: 'string',
        description:
          "Soul DID URI (e.g. 'did:platform-x:soul:spry-engage') or soul slug (e.g. 'spry-engage').",
      },
    },
    targetedVariants: {
      type: 'array',
      description:
        "Variant references this work item targets per RFC-0017 §5.4. Each entry is a path-style URI in the format 'did:{method}:{platform}:soul:{soul-id}/variant:{variant-id}' (OQ-6 resolution). When non-empty, admission scoring routes Sα₁ + Sα₂ through variant-scoped fields instead of soul-aggregate. Empty or absent = soul-aggregate scoring (backward-compatible with RFC-0009 baseline).",
      items: {
        type: 'string',
        pattern: '^did(?::[^:]+)+:soul:[a-z][a-z0-9-]*/variant:[a-z][a-z0-9-]*$',
        description:
          "Path-style variant URI per RFC-0017 OQ-6: 'did:{method}:{platform}:soul:{soul-id}/variant:{variant-id}'. The explicit 'variant:' keyword preserves the parent/child hierarchy and composes with future RFC-0018 Journey partition types.",
      },
    },
  },
  additionalProperties: true,
} as const;

